  ('judicial-a9db9bda-moex-00157', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-110-2758c184', 'sub-judicial-a9db9bda-01', NULL, 'essay', '為了有效遏止電信詐欺，我國立法者於 2018 年修正組織犯罪防制條例
第 2 條，將詐騙集團犯罪納入規範。司法實務上，提款車手往往居於經
濟弱勢，但因為負責提領詐騙款項，而被認定成立組織犯罪防制條例第
3 條第 1 項後段之罪。試問以組織犯罪防制條例對抗詐騙集團犯罪（尤
其是針對取款車手的部分）在刑事政策上會有何問題？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "9b712b4a9e56", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "114", "s": "0519", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事政策", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00158', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-110-2758c184', 'sub-judicial-a9db9bda-01', NULL, 'essay', '刑法第91條之1乃是國家針對性犯罪者實施刑後強制治療之法定依據。
請說明刑後強制治療之目的與現行規定之爭議，以及與此議題相關的司
法院釋字第 799號解釋之主要論據為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "9b712b4a9e56", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "114", "s": "0519", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事政策", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00159', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-110-2758c184', 'sub-judicial-a9db9bda-01', NULL, 'essay', '依刑法第58 條規定：「科罰金時，除依前條規定外，並應審酌犯罪行為
人之資力及犯罪所得之利益。如所得之利益超過罰金最多額時，得於所
得利益之範圍內酌量加重。」法官決定罰金範圍時，得在犯罪所得之範
圍內加重罰金數額。請說明罰金刑與沒收犯罪所得之規範目的為何，並
且由此評析此一規定是否合理。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "9b712b4a9e56", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "114", "s": "0519", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事政策", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00160', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-110-2758c184', 'sub-judicial-a9db9bda-01', NULL, 'essay', '從近年的修法結果來看，例如刑法第 276 條之過失致死罪、刑法第 185
條之 3 之不能安全駕駛罪，以及食品安全衛生管理法第 49 條第 1 項之
攙偽假冒罪，均可看到重刑化的立法趨勢。請說明重刑立法的立論依據，
以及可能產生的影響為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "9b712b4a9e56", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "114", "s": "0519", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事政策", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00161', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-110-765a1059', 'sub-judicial-a9db9bda-02', NULL, 'essay', '甲攜帶鐵鎚於夜間行經繁華的商業區，見停放路邊之名貴私人跑車一
輛，乃決意侵入該車竊取財物。隨後甲以鐵鎚打破駕駛座車窗，剛探頭
入內時，就被行經該處的巡邏員警發現而逮捕。試問，依照刑法之規定，
甲之行為應如何論罪？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "b0b4869b5ae9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "114", "s": "0506", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與少年事件處理法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00162', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-110-765a1059', 'sub-judicial-a9db9bda-02', NULL, 'essay', '甲以貸款方式購買一棟透天厝之後，其配偶乙因故自殺於該屋內。甲迅
速為乙辦完後事後一週，因不堪貸款負荷，欲將該房屋脫手，乃打聽附
近兇宅行情後以自己名義張貼公告，其內容僅有「屋齡淺、屋況佳，脫
手變現」及售價新臺幣（以下同）三百萬元。再經二週，丙看到公告而
與甲聯繫表示欲購買該房屋。甲與丙交涉後，於簽約時，丙詢問該房屋
是否為半年內曾有自殺或兇殺案之兇宅？甲答否。丙因此支付三百萬元
予甲並將該房屋移轉登記至自己名下。丙搬入後不久，偶然自從事不動
產仲介業之鄰居口中得知其所購房屋最近有人在內自殺，否則行情至少
有六百萬元，乃憤而向檢察官提起詐欺罪告訴。試問，依照刑法之規定，
甲之行為應如何論罪？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "b0b4869b5ae9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "114", "s": "0506", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與少年事件處理法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL),
  ('judicial-a9db9bda-moex-00163', 'judicial-a9db9bda', 'judicial-a9db9bda-moex-110-765a1059', 'sub-judicial-a9db9bda-02', NULL, 'essay', '16 歲之少年甲因有觸犯強盜罪之嫌疑，經警察移送少年法院，少年法院
調查過程中，甲矢口否認犯罪。法院因查無相關證據可認定甲有被移送
之事實，於是作成不付審理之裁定，並告確定。其後，警察就同一強盜
事件，循線發現另有少年乙、丙共同參與對被害人之強盜行為，乃將乙、
丙移送少年法院。法院調查時，乙、丙在法庭上陳述甲才是本件強盜行
為的主謀，且行為時在現場指揮與把風，法院再傳喚甲到庭作證與對質
後，甲始承認確實有參與強盜行為之計畫與實行。因此，法院乃類推適
用少年事件處理法第 64 條之 2 第 1 項第 2 款規定，裁定重新審理。試
問，依照少年事件處理法，詳述法院之裁定是否適法？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "b0b4869b5ae9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "114", "s": "0506", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與少年事件處理法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監獄官"}'::jsonb, NULL)
